class Solution {
public:
	int countTrailingZeros(int n) {
		int count = 0;
		int i = 0;
		while (n > 0) {
			if (n & 1 == 0) {
				count++;
			}
			n >>= 1;
			i++;
		}
		return count;
	}
};

